mapper.select:
select count(*)
from information_schema.tables
where table_schema = current_schema() and table_name = #{tableName}

select count(*)
from information_schema.columns
where table_schema = current_schema()
  and table_name = #{tableName}
  and column_name = #{columnName}

select count(*)
from pg_indexes
where schemaname = current_schema() and indexname = #{indexName}

select r.id, r.archive_level, r.parent_id, r.fonds_code, r.fonds_name, r.category_code, r.category_name, r.archive_no, r.electronic_status, r.archive_year, r.display_order, r.locked_flag, r.lock_reason, r.locked_by, r.locked_at ${selectColumns} from am_archive_record r join ${tableName} d on d.id = r.id where r.deleted_flag = false and d.deleted_flag = false and r.archive_level = #{archiveLevel}
and r.fonds_code = #{fondsCode}
and d.${condition.columnName} = #{condition.value}
and d.${condition.columnName} >= #{condition.value}
and d.${condition.columnName} <= #{condition.value}
and r.id in
#{recordId}
order by
array_position(array[
cast(#{recordId} as bigint)
], r.id)
r.sort_order, r.id desc

mapper.update:
update ${tableName}
set

    ${assignment.columnName} = #{assignment.value}

    , updated_at = localtimestamp
where id = #{id} and deleted_flag = false

update ${tableName}
set deleted_flag = true, updated_at = localtimestamp
where id = #{id} and deleted_flag = false

mapper.select:
select *
from ${tableName}
where id = #{id} and deleted_flag = false
